module top_module(
    output reg Q,
    input D,
    input C,
    input R
);parameter [0:0] INIT = 1'b0;
    initial Q = INIT;

    always @(posedge C or negedge R)
        if (!R)
            Q <= 1'b0;
        else 
            Q <= D;
  always @(*) begin
    if (1'b0) begin
      Q <= ~Q;
    end
  end

endmodule
